// Statistics: total count and most popular tags – protected endpoint
app.get('/stats', authRequired, (req, res) => {
  const bookmarks = loadBookmarks();
  const total = bookmarks.length;
  const tagCounts = {};
  bookmarks.forEach(bm => {
    bm.tags.forEach(tag => {
      tagCounts[tag] = (tagCounts[tag] || 0) + 1;
    });
  });
  // Sort tags by frequency descending, take top 5
  const popularTags = Object.entries(tagCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([tag, count]) => ({ tag, count }));
  res.json({ totalBookmarks: total, popularTags });
});

// Basic health check
app.get('/health', (req, res) => res.send('OK'));
// 404 handler for unknown routes
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// Generic error handler to avoid leaking stack traces
app.use((err, req, res, next) => {
  console.error(err);
  res.status(500).json({ error: 'Internal Server Error' });
});

// Update endpoint – modify existing bookmark
app.put('/bookmarks/:id', authRequired, (req, res) => {
  const { id } = req.params;
  const payload = req.body;
  const errors = validateBookmark(payload);
  if (errors.length) return res.status(400).json({ errors });
  const bookmarks = loadBookmarks();
  const index = bookmarks.findIndex(b => b.id === id);
  if (index === -1) return res.status(404).json({ error: 'Bookmark not found' });
  const existing = bookmarks[index];
  const updatedBm = {
    ...existing,
    title: sanitize(payload.title),
    url: payload.url,
    description: sanitize(payload.description || ''),
    tags: payload.tags ? payload.tags.map(t => sanitize(t.trim())).filter(Boolean) : [],
    updatedAt: new Date().toISOString()
  };
  const updated = [...bookmarks];
  updated[index] = updatedBm;
  saveBookmarks(updated);
  res.json(updatedBm);
});

// Delete endpoint – remove bookmark by id
app.delete('/bookmarks/:id', authRequired, (req, res) => {
  const { id } = req.params;
  const bookmarks = loadBookmarks();
  const index = bookmarks.findIndex(b => b.id === id);
  if (index === -1) return res.status(404).json({ error: 'Bookmark not found' });
  const updated = bookmarks.filter(b => b.id !== id);
  saveBookmarks(updated);
  res.status(204).send();
});

const PORT = process.env.PORT || 3000;
if (require.main === module) {
  app.listen(PORT, () => console.log(`LinkVault server listening on port ${PORT}`));
}

module.exports = { app, DATA_FILE, resetData: () => {
  bookmarks = [];
  // Clear persisted file as well for test isolation
  try {
    fs.writeFileSync(DATA_FILE, JSON.stringify([], null, 2), 'utf-8');
  } catch (err) {
    console.error('Failed to reset data file:', err);
  }
} };

// Frontend script for LinkVault UI
(() => {
  const apiBase = '';
  const getToken = () => document.getElementById('token').value.trim();
  const authHeader = () => {
    const token = getToken();
    return token ? { Authorization: `Bearer ${token}` } : {};
  };

  // Elements
  const bookmarkListEl = document.getElementById('bookmark-list');
  const statsEl = document.getElementById('stats');
  const form = document.getElementById('bookmark-form');
  const searchInput = document.getElementById('search-input');
  const searchBtn = document.getElementById('search-btn');
  const clearSearchBtn = document.getElementById('clear-search');
  // Modal controls
  const openAddModalBtn = document.getElementById('open-add-modal');
  const closeAddModalBtn = document.getElementById('close-add-modal');
  const addModal = document.getElementById('add-modal');

  // Modal toggle listeners
  if (openAddModalBtn) {
    openAddModalBtn.addEventListener('click', () => addModal.classList.remove('hidden'));
  }
  if (closeAddModalBtn) {
    closeAddModalBtn.addEventListener('click', () => addModal.classList.add('hidden'));
  }

  // Load all bookmarks initially
  let currentBookmarks = [];
  let filterTag = null; // active tag filter

  function renderStats(total, popularTags) {
    const tagsHtml = popularTags.map(t => `<span class="tag" data-tag="${t.tag}">${t.tag} (${t.count})</span>`).join(' ');
    statsEl.innerHTML = `<h2>Stats</h2><p>Total bookmarks: ${total}</p><p>Popular tags: ${tagsHtml}</p>`;
    // Attach click listeners to popular tag filters
    statsEl.querySelectorAll('.tag').forEach(el => {
      el.addEventListener('click', () => { filterTag = el.dataset.tag; loadBookmarks(); });
    });
  }

  function renderBookmarks(list) {
    if (list.length === 0) {
      bookmarkListEl.innerHTML = '<p>No bookmarks found.</p>';
      return;
    }
    const html = list.map(b => {
      const tagsHtml = b.tags.map(t => `<span class="tag" data-tag="${t}">${t}</span>`).join(' ');
      return `
        <div class="bookmark-item" data-id="${b.id}">
          <a href="${b.url}" target="_blank" rel="noopener" class="bookmark-title">${b.title}</a>
          ${b.description ? `<p>${b.description}</p>` : ''}
          <div>${tagsHtml}</div>
          <button class="delete-btn" title="Delete">✕</button>
        </div>`;
    }).join('');
    bookmarkListEl.innerHTML = html;
    // Tag click filter
    bookmarkListEl.querySelectorAll('.tag').forEach(el => {
      el.addEventListener('click', () => { filterTag = el.dataset.tag; loadBookmarks(); });
    });
    // Delete handlers
    bookmarkListEl.querySelectorAll('.delete-btn').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        const id = e.target.closest('.bookmark-item').dataset.id;
        await fetch(`${apiBase}/bookmarks/${id}`, { method: 'DELETE', headers: authHeader() });
        loadBookmarks();
      });
    });
  }

  async function loadBookmarks() {
    try {
      const url = new URL('/bookmarks', window.location.origin);
      if (filterTag) url.searchParams.append('tag', filterTag);
      const res = await fetch(url, { headers: authHeader() });
      if (!res.ok) throw new Error('Failed to load bookmarks');
      currentBookmarks = await res.json();
      renderBookmarks(currentBookmarks);
    } catch (e) {
      console.error(e);
    }
  }

  async function loadStats() {
    try {
      const res = await fetch('/stats', { headers: authHeader() });
      if (!res.ok) throw new Error('Failed to load stats');
      const data = await res.json();
      renderStats(data.totalBookmarks, data.popularTags);
    } catch (e) {
      console.error(e);
    }
  }

  // Search handler
  async function performSearch(term) {
    if (!term) return loadBookmarks();
    const url = new URL('/search', window.location.origin);
    url.searchParams.append('q', term);
    const res = await fetch(url, { headers: authHeader() });
    if (res.ok) {
      const results = await res.json();
      renderBookmarks(results);
    }
  }

  // Form submit handler to add bookmark
  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    const title = document.getElementById('title').value.trim();
    const urlVal = document.getElementById('url').value.trim();
    const description = document.getElementById('description').value.trim();
    const tagsRaw = document.getElementById('tags').value;
    const tags = tagsRaw.split(',').map(t => t.trim()).filter(Boolean);
    const payload = { title, url: urlVal, description, tags };
    try {
      const res = await fetch('/bookmarks', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', ...authHeader() },
        body: JSON.stringify(payload),
      });
      if (!res.ok) throw new Error('Failed to add');
      // Reset form
      form.reset();
      // Close modal after adding
      addModal.classList.add('hidden');
      filterTag = null;
      await loadBookmarks();
      await loadStats();
    } catch (err) {
      console.error(err);
    }
  });

  searchBtn.addEventListener('click', () => performSearch(searchInput.value.trim()));
  clearSearchBtn.addEventListener('click', () => { searchInput.value = ''; filterTag = null; loadBookmarks(); });

  // Initial load
  loadBookmarks();
  loadStats();
})();

const request = require('supertest');
const fs = require('fs');
const path = require('path');

// Import the app and DATA_FILE constant
const { app, DATA_FILE, resetData } = require('./server');

// Helper to reset in-memory data before each test
function resetInMemory() {
  // Use the exported resetData function from server module
  resetData();
}

// Set a test API token for authentication
process.env.API_TOKEN = 'test-secret-token';
function authHeader() {
  return { Authorization: `Bearer ${process.env.API_TOKEN}` };
}

describe('LinkVault API', () => {
  beforeEach(() => {
    resetInMemory();
  });

  test('POST /bookmarks creates a bookmark', async () => {
    const payload = {
      title: 'OpenAI',
      url: 'https://openai.com',
      description: 'AI research lab',
      tags: ['ai', 'research']
    };
    const res = await request(app).post('/bookmarks').set(authHeader()).send(payload);
    expect(res.statusCode).toBe(201);
    expect(res.body).toMatchObject({
      title: payload.title,
      url: payload.url,
      description: payload.description,
      tags: payload.tags
    });
    expect(typeof res.body.id).toBe('string');
  });

  test('GET /bookmarks returns list and can filter by tag', async () => {
    // Create two bookmarks
    await request(app).post('/bookmarks').set(authHeader()).send({ title: 'A', url: 'http://a.com', tags: ['foo'] });
    await request(app).post('/bookmarks').set(authHeader()).send({ title: 'B', url: 'http://b.com', tags: ['bar'] });

    const allRes = await request(app).get('/bookmarks').set(authHeader());
    expect(allRes.statusCode).toBe(200);
    expect(allRes.body.length).toBe(2);

    const fooRes = await request(app).get('/bookmarks').set(authHeader()).query({ tag: 'foo' });
    expect(fooRes.statusCode).toBe(200);
    expect(fooRes.body.length).toBe(1);
    expect(fooRes.body[0].title).toBe('A');
  });

  test('GET /search finds bookmarks by title or description', async () => {
    await request(app).post('/bookmarks').set(authHeader()).send({ title: 'Node.js', url: 'http://nodejs.org', description: 'JavaScript runtime' });
    const res = await request(app).get('/search').set(authHeader()).query({ q: 'javascript' });
    expect(res.statusCode).toBe(200);
    expect(res.body.length).toBe(1);
    expect(res.body[0].title).toBe('Node.js');
  });

  test('GET /stats returns total count and popular tags', async () => {
    await request(app).post('/bookmarks').set(authHeader()).send({ title: 'One', url: 'http://one', tags: ['common'] });
    await request(app).post('/bookmarks').set(authHeader()).send({ title: 'Two', url: 'http://two', tags: ['common', 'extra'] });
    const res = await request(app).get('/stats').set(authHeader());
    expect(res.statusCode).toBe(200);
    expect(res.body.totalBookmarks).toBe(2);
    // popularTags should include 'common' with count 2
    const commonTag = res.body.popularTags.find(t => t.tag === 'common');
    expect(commonTag).toBeDefined();
    expect(commonTag.count).toBe(2);
  });
});

